// ============================================
// OTIF Scorecard: Aggregate Shipments by Week
// ============================================
// Input: raw shipment records with on-time flags and lead times
// Output: one item per week with aggregated KPIs

const shipments = $input.all().map(i => i.json);

if (shipments.length === 0) {
  return [{ json: { error: 'No shipments found', count: 0 } }];
}

// Group by ISO week (Monday start)
const byWeek = {};
for (const s of shipments) {
  const dt = new Date(s.Order_Time);
  const day = dt.getDay();
  const monday = new Date(dt);
  monday.setDate(dt.getDate() - ((day + 6) % 7));
  const weekKey = monday.toISOString().slice(0, 10);

  if (!byWeek[weekKey]) byWeek[weekKey] = [];
  byWeek[weekKey].push(s);
}

// Compute KPIs per week
const results = [];
for (const [weekStart, rows] of Object.entries(byWeek)) {
  const n = rows.length;
  const onTime = rows.filter(r => r.Delivery_OnTime === true).length;

  // Week end (Sunday)
  const monday = new Date(weekStart);
  const sunday = new Date(monday);
  sunday.setDate(monday.getDate() + 6);
  const weekEnd = sunday.toISOString().slice(0, 10);

  // ISO week number
  const d = new Date(weekStart);
  d.setDate(d.getDate() + 3 - ((d.getDay() + 6) % 7));
  const yearStart = new Date(d.getFullYear(), 0, 1);
  const weekNum = Math.ceil((((d - yearStart) / 86400000) + 1) / 7);

  results.push({
    json: {
      Name: `Week ${weekNum}`,
      weekStart: weekStart,
      weekEnd: weekEnd,
      totalShipments: n,
      onTimeDeliveries: onTime,
      avgLeadTimeDays: Math.round(rows.reduce((s, r) => s + (r.LT_Days || 0), 0) / n * 10) / 10,
      avgLeadTimeHrs: Math.round(rows.reduce((s, r) => s + (r.LT_Hours || 0), 0) / n * 10) / 10,
      transmissionOnTime: Math.round(rows.filter(r => r.Transmission_OnTime === true).length / n * 1000) / 10,
      loadingOnTime: Math.round(rows.filter(r => r.Loading_OnTime === true).length / n * 1000) / 10,
      airportOnTime: Math.round(rows.filter(r => r.Airport_OnTime === true).length / n * 1000) / 10,
      landingOnTime: Math.round(rows.filter(r => r.Landing_OnTime === true).length / n * 1000) / 10,
      deliveryOnTime: Math.round(onTime / n * 1000) / 10,
      lateShipments: n - onTime
    }
  });
}

// Sort by weekStart ascending
results.sort((a, b) => a.json.weekStart.localeCompare(b.json.weekStart));

return results;

// ============================================
// Prepare Global Summary Prompt
// ============================================
// Collects all weekly KPIs into a single prompt for the global AI analysis

const items = $input.all();
const weeks = items.map(i => i.json);

weeks.sort((a, b) => a.weekStart.localeCompare(b.weekStart));

let summary = 'Here are the weekly OTIF scorecards for retail logistics:\n\n';
for (const w of weeks) {
  const otif = Math.round(w.onTimeDeliveries / w.totalShipments * 1000) / 10;
  summary += `${w.Name} (${w.weekStart} to ${w.weekEnd}):\n`;
  summary += `  Shipments: ${w.totalShipments}, On-Time: ${w.onTimeDeliveries}, Late: ${w.lateShipments}, OTIF: ${otif}%\n`;
  summary += `  Avg Lead Time: ${w.avgLeadTimeDays} days\n`;
  summary += `  Checkpoints: Transmission ${w.transmissionOnTime}%, Loading ${w.loadingOnTime}%, Airport ${w.airportOnTime}%, Landing ${w.landingOnTime}%, Delivery ${w.deliveryOnTime}%\n\n`;
}

return [{ json: { globalPrompt: summary } }];
